INSERT INTO gemstone_predictions (
    lagna, planets_in_1st, planets_in_5th, planets_in_9th,
    overall_prediction_male, overall_prediction_female,
    health_prediction_male, health_prediction_female,
    education_prediction_male, education_prediction_female,
    love_prediction_male, love_prediction_female,
    luck_prediction_male, luck_prediction_female,
    overall_gemstone, health_gemstone, education_gemstone, love_gemstone, luck_gemstone
) VALUES (
    'मेष',
    'मंगल',
    'सूर्य, बुध',
    'गुरु',
    'तपाईँको मेष लग्नको राशिको हुनुहुन्छ — एक जोशिलो र साहसी व्यक्तित्व। पहिलो भावमा मंगल हुनाले तपाईँमा असाधारण ऊर्जा र निर्भीकता देखिन्छ। पाँचौं भावमा सूर्य र बुधको संयोग तपाईँलाई बुद्धिमान र सिर्जनशील बनाउँछ — मन सधैँ सक्रिय रहन्छ। नवौं भावमा गुरुको उपस्थितिले तपाईँको भाग्य र आध्यात्मिक यात्रालाई सहारा दिन्छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँ एक दृढ, सफल र भाग्यशाली व्यक्ति हुनुहुन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Yellow Sapphire धारण गर्नु लाभदायक हुनेछ।',
    'तपाईँको मेष लग्नको राशिको हुनुहुन्छ — स्वाभिमानी र जोशिली स्वभावकी। पहिलो भावमा मंगलले तपाईँमा आत्मविश्वास र नेतृत्व क्षमता दिन्छ। पाँचौं भावमा सूर्य र बुधको संयोगले तपाईँलाई चतुर र प्रतिभाशाली बनाउँछ। नवौं भावमा गुरु हुनाले भाग्य तपाईँको साथमा छ र जीवनका राम्रा अवसरहरू आउन सक्छन्। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवनयात्रा उज्यालो र अर्थपूर्ण देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Yellow Sapphire धारण गर्नु लाभदायक हुनेछ।',
    'मंगल पहिलो भावमा हुनाले तपाईँको शरीर ऊर्जाले भरिएको छ। तपाईँमा स्फूर्ति र साहस दुवै देखिन्छ। तर कहिलेकाहीँ अत्यधिक उत्साहले शरीरमा थकान महसुस हुन सक्छ। नियमित आराम र सन्तुलित खानपानले स्वास्थ्य राम्रो राख्न सकिन्छ। यसलाई अझ राम्रो बनाउन Red Coral धारण गर्नु सहयोगी हुनेछ।',
    'पहिलो भावको मंगलले तपाईँलाई शारीरिक रूपमा सक्रिय र बलियो बनाउँछ। तर मानसिक तनाव कहिलेकाहीँ बढ्न सक्छ — आफ्नो मनलाई शान्त राख्न सचेत रहनु आवश्यक छ। योग वा ध्यानले राम्रो सहयोग पुर्‍याउँछ। स्वास्थ्यलाई अझ सुदृढ बनाउन Red Coral धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा सूर्य र बुधको उपस्थिति तपाईँको बौद्धिक क्षमतालाई उच्च बनाउँछ। पढाइमा तपाईँ ध्यान केन्द्रित गर्न सक्नुहुन्छ र नयाँ कुरा छिटो सिक्ने स्वभाव देखिन्छ। प्रतियोगितामा पनि राम्रो प्रदर्शन गर्न सक्नुहुन्छ। शिक्षामा थप सफलता ल्याउन Colombian Emerald धारण गर्नु उपयुक्त हुनेछ।',
    'पाँचौं भावमा सूर्य र बुधको संयोगले तपाईँलाई पढाइमा तीव्र र जिज्ञासु बनाउँछ। गणित, विज्ञान वा साहित्य — जुनसुकै क्षेत्रमा पनि तपाईँ राम्रो गर्न सक्नुहुन्छ। परीक्षाको समयमा मन स्थिर राख्नाले परिणाम राम्रो आउँछ। शिक्षामा उत्कृष्टता ल्याउन Colombian Emerald धारण गर्नु सहयोगी हुनेछ।',
    'पाँचौं भावमा सूर्य र बुधको संयोगले प्रेम सम्बन्धमा बौद्धिक आकर्षण र संवादको महत्त्व देखिन्छ। तपाईँ आफ्नो साथीसँग खुलेर कुरा गर्न रुचाउनुहुन्छ। सम्बन्धमा ईमानदारी र पारदर्शिता राख्नाले सम्बन्ध टिकाउ हुन्छ। प्रेममा सुमधुरता ल्याउन Ruby Stone धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा सूर्य र बुधले प्रेम सम्बन्धमा स्पष्टता र भावनात्मक परिपक्वता ल्याउँछ। तपाईँ मनको कुरा सिधै भन्न रुचाउनुहुन्छ। साथीले तपाईँको बुद्धिमत्ता र व्यक्तित्वलाई मन पराउँछन्। सम्बन्धलाई अझ गहिरो र मजबुत बनाउन Ruby Stone धारण गर्नु उपयुक्त हुनेछ।',
    'नवौं भावमा गुरुको उपस्थितिले तपाईँको भाग्य साथ दिन्छ। जीवनमा राम्रा अवसरहरू आउन सक्छन् र ती अवसर चिन्न तपाईँलाई सहज हुन्छ। धर्म र ज्ञानप्रति रुचि राख्नाले जीवनमा दिशा मिल्छ। भाग्यलाई झनै बलियो बनाउन Yellow Sapphire धारण गर्नु अत्यन्त उत्तम हुनेछ।',
    'नवौं भावमा गुरु हुनाले तपाईँको जीवनमा एक सकारात्मक शक्ति सधैँ काम गरिरहन्छ। यात्रा, शिक्षा र आध्यात्मिकतामा तपाईँलाई विशेष लाभ देखिन्छ। परिवार र गुरुजनको आशीर्वाद जीवनलाई समृद्ध बनाउँछ। भाग्यलाई अझ उज्यालो बनाउन Yellow Sapphire धारण गर्नु लाभदायक हुनेछ।',
    'Yellow Sapphire', 'Red Coral', 'Colombian Emerald', 'Ruby Stone', 'Yellow Sapphire'
);

INSERT INTO gemstone_predictions (
    lagna, planets_in_1st, planets_in_5th, planets_in_9th,
    overall_prediction_male, overall_prediction_female,
    health_prediction_male, health_prediction_female,
    education_prediction_male, education_prediction_female,
    love_prediction_male, love_prediction_female,
    luck_prediction_male, luck_prediction_female,
    overall_gemstone, health_gemstone, education_gemstone, love_gemstone, luck_gemstone
) VALUES (
    'मेष',
    'शनि, राहु',
    'चन्द्र',
    'शुक्र',
    'तपाईँको मेष लग्नको राशिको हुनुहुन्छ। पहिलो भावमा शनि र राहुको संयोग जीवनमा केही जटिलताहरू ल्याउन सक्छ — तर यो अनुभव तपाईँलाई बलियो पनि बनाउँछ। पाँचौं भावमा चन्द्रमाले भावनात्मक गहिराई दिन्छ र पढाइ तथा सिर्जनामा संवेदनशीलता देखिन्छ। नवौं भावमा शुक्रले जीवनमा सौन्दर्य र प्रेमको रंग थप्छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवनमा संघर्षपछि सफलता र सुन्दरता दुवै पर्खिरहेका छन्। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Opal Stone धारण गर्नु लाभदायक हुनेछ।',
    'तपाईँको मेष लग्नको राशिको हुनुहुन्छ। पहिलो भावमा शनि र राहुको उपस्थितिले जीवनमा धैर्य र अनुशासनको आवश्यकता देखाउँछ। पाँचौं भावमा चन्द्रमाले तपाईँलाई भावनात्मक रूपमा समृद्ध बनाउँछ। नवौं भावमा शुक्रले सौभाग्य र सौन्दर्यप्रियतालाई बढाउँछ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँमा दृढता र कोमलताको अद्भुत मिश्रण देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Opal Stone धारण गर्नु लाभदायक हुनेछ।',
    'पहिलो भावमा शनि र राहुको संयोगले स्वास्थ्यमा थकान, जोड्नी दुखाइ वा मानसिक तनाव महसुस हुन सक्छ। नियमित दिनचर्या र पर्याप्त निद्राले स्वास्थ्य राम्रो राख्न सकिन्छ। आफ्नो शरीरलाई बेलैमा ध्यान दिनु आवश्यक छ। स्वास्थ्यलाई सुदृढ बनाउन Amethyst धारण गर्नु उपयुक्त हुनेछ।',
    'शनि र राहुको प्रभावले कहिलेकाहीँ अनावश्यक चिन्ता र तनाव आउन सक्छ। मन शान्त राख्न ध्यान वा प्राणायाम गर्नु राम्रो हुन्छ। आफ्नो खाने बानी र आराममा विशेष ध्यान दिनु आवश्यक छ। स्वास्थ्य सन्तुलन ल्याउन Amethyst धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा चन्द्रमाले पढाइमा कल्पनाशीलता र भावनात्मक बुद्धिमत्ता दिन्छ। तर मन कहिलेकाहीँ चंचल हुन सक्छ — एकाग्रता बढाउन प्रयास गर्नु उपयुक्त हुन्छ। सिर्जनात्मक विषयमा विशेष रुचि र प्रतिभा देखिन्छ। शिक्षामा प्रगति ल्याउन Pearl धारण गर्नु सहयोगी हुनेछ।',
    'पाँचौं भावको चन्द्रमाले तपाईँलाई पढाइमा भावनात्मक जोड दिन्छ — विषयसँग गहिरो सम्बन्ध बनाउन सक्नुहुन्छ। स्मरण शक्ति राम्रो छ तर ध्यान स्थिर राख्न थोडै प्रयास चाहिन्छ। शिक्षामा सफलता ल्याउन Pearl धारण गर्नु उत्तम हुनेछ।',
    'पाँचौं भावमा चन्द्रमाले प्रेम सम्बन्धमा गहिरो भावना र संवेदनशीलता देखाउँछ। तपाईँ साथीको भावनालाई सजिलै बुझ्न सक्नुहुन्छ। तर अत्यधिक भावुकताले कहिलेकाहीँ गलतफहमी हुन सक्छ — सन्तुलन राख्नु राम्रो हुन्छ। प्रेम सम्बन्धलाई सुन्दर बनाउन Moonstone धारण गर्नु लाभदायक हुनेछ।',
    'चन्द्रमाको प्रभावले प्रेममा कोमलता र गहिरो बन्धन देखिन्छ। तपाईँ साथीलाई मनले साँच्चै माया गर्नुहुन्छ। संवाद र भावनाको आदान-प्रदान सम्बन्धलाई मजबुत बनाउँछ। प्रेमलाई अझ मधुर बनाउन Moonstone धारण गर्नु उपयुक्त हुनेछ।',
    'नवौं भावमा शुक्रको उपस्थितिले जीवनमा सुन्दरता, कला र सुखको अनुभव ल्याउँछ। भाग्य खुल्दा जीवनमा आनन्ददायी परिस्थितिहरू आउन सक्छन्। विदेश वा यात्रासम्बन्धी अवसर पनि देखिन्छ। भाग्यलाई बलियो बनाउन Opal Stone धारण गर्नु लाभदायक हुनेछ।',
    'नवौं भावको शुक्रले तपाईँको जीवनमा सौन्दर्य र समृद्धि ल्याउँछ। सांस्कृतिक, सामाजिक वा कलासम्बन्धी क्षेत्रमा भाग्य साथ दिन्छ। अनुकूल समयमा सही निर्णय लिनाले जीवन झनै राम्रो हुन्छ। भाग्य ल्याउन Opal Stone धारण गर्नु उत्तम हुनेछ।',
    'Opal Stone', 'Amethyst', 'Pearl', 'Moonstone', 'Opal Stone'
);

