    overall_gemstone, health_gemstone, education_gemstone, love_gemstone, luck_gemstone
) VALUES (
    'वृषभ',
    'शुक्र, चन्द्र',
    'बुध',
    'शनि',
    'तपाईँको वृषभ लग्नको राशिको हुनुहुन्छ — स्थिर, धैर्यशील र सौन्दर्यप्रिय स्वभाव। पहिलो भावमा शुक्र र चन्द्रको संयोग तपाईँलाई अत्यन्त आकर्षक व्यक्तित्वका धनी बनाउँछ। पाँचौं भावमा बुधले बौद्धिक तीक्ष्णता र सञ्चारकला दिन्छ। नवौं भावमा शनिले जीवनमा मेहनत र अनुशासनबाट भाग्य खुल्ने संकेत दिन्छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवनयात्रा सुन्दर, व्यवस्थित र फलदायी देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Zambian Emerald धारण गर्नु लाभदायक हुनेछ।',
    'तपाईँको वृषभ लग्नको राशिको हुनुहुन्छ — सुकोमल, कलाप्रिय र भरोसायोग्य स्वभाव। पहिलो भावमा शुक्र र चन्द्रको उपस्थितिले तपाईँमा स्वाभाविक सौन्दर्य र माया गर्ने क्षमता छ। पाँचौं भावमा बुधले तपाईँलाई चतुर र भाषामा कुशल बनाउँछ। नवौं भावमा शनिले धैर्यपूर्वक काम गर्नेलाई फल दिन्छ भनी संकेत गर्छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन कोमलता र दृढताको सुन्दर संगमजस्तो छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Zambian Emerald धारण गर्नु लाभदायक हुनेछ।',
    'शुक्र र चन्द्रको संयोगले तपाईँलाई भावनात्मक रूपमा संवेदनशील बनाउँछ — मन र शरीर दुवैमा कोमलता छ। त्वचा र हार्मोनसम्बन्धी समस्याहरूमा ध्यान दिनु आवश्यक हुन सक्छ। पर्याप्त आराम र जलपान स्वास्थ्यका लागि महत्त्वपूर्ण छ। स्वास्थ्यलाई राम्रो राख्न Moonstone धारण गर्नु उपयुक्त हुनेछ।',
    'पहिलो भावमा शुक्र र चन्द्रले तपाईँलाई शारीरिक रूपमा आकर्षक र मानसिक रूपमा संवेदनशील बनाउँछ। तनावलाई बेलैमा पहिचान गरी आफूलाई समय दिनु राम्रो हुन्छ। स्वास्थ्य सन्तुलनका लागि Moonstone धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा बुध हुनाले पढाइमा तपाईँको विश्लेषण क्षमता उत्कृष्ट छ। भाषा, गणित वा सञ्चारसम्बन्धी विषयमा विशेष रुचि देखिन्छ। लेख्ने र बोल्ने कलामा पनि प्रतिभा छ। शिक्षामा झनै उन्नति ल्याउन Zambian Emerald धारण गर्नु उपयुक्त हुनेछ।',
    'बुधको प्रभावले पढाइमा तर्कशक्ति र जिज्ञासा दुवै छ। विज्ञान, लेखन वा प्रविधिमा करियर बनाउन उत्तम देखिन्छ। शिक्षामा सफलता ल्याउन Zambian Emerald धारण गर्नु राम्रो हुनेछ।',
    'पाँचौं भावमा बुधले प्रेम सम्बन्धमा संवाद र मित्रता महत्त्वपूर्ण भूमिका खेल्छ। तपाईँ साथीसँग कुरा गर्न र विचार साझा गर्न रुचाउनुहुन्छ। बौद्धिक मेल भएको साथी तपाईँका लागि उपयुक्त देखिन्छ। प्रेम सम्बन्धलाई समृद्ध बनाउन Pink Tourmaline धारण गर्नु लाभदायक हुनेछ।',
    'बुधको प्रभावले प्रेम सम्बन्धमा खुलापन र बौद्धिक आकर्षण देखिन्छ। साथीसँग विचार मिल्दा सम्बन्ध गहिरो हुन्छ। भावनाको सही अभिव्यक्तिले सम्बन्धलाई मजबुत बनाउँछ। प्रेमलाई अझ सुन्दर बनाउन Pink Tourmaline धारण गर्नु उपयुक्त हुनेछ।',
    'नवौं भावमा शनिले भाग्यका लागि धैर्य र कडा परिश्रमको आवश्यकता देखाउँछ। तर एकपटक भाग्य खुल्यो भने त्यो स्थायी र टिकाउ हुन्छ। जिम्मेवारी र अनुशासनले जीवनलाई सही दिशामा लैजान्छ। भाग्यलाई अनुकूल बनाउन Blue Sapphire धारण गर्नु लाभदायक हुनेछ।',
    'नवौं भावको शनिले जीवनमा अनुशासन र नैतिकताले भाग्य खुल्ने संकेत दिन्छ। मेहनतको फल ढिलो आए पनि पक्कै आउँछ भन्ने विश्वास राख्नु राम्रो हुन्छ। भाग्य सन्तुलनका लागि Blue Sapphire धारण गर्नु उत्तम हुनेछ।',
    'Zambian Emerald', 'Moonstone', 'Zambian Emerald', 'Pink Tourmaline', 'Blue Sapphire'
);

INSERT INTO gemstone_predictions (
    lagna, planets_in_1st, planets_in_5th, planets_in_9th,
    overall_prediction_male, overall_prediction_female,
