    overall_gemstone, health_gemstone, education_gemstone, love_gemstone, luck_gemstone
) VALUES (
    'वृषभ',
    'सूर्य',
    'मंगल, गुरु',
    'राहु',
    'तपाईँको वृषभ लग्नको राशिको हुनुहुन्छ। पहिलो भावमा सूर्यले तपाईँमा आत्मविश्वास र नेतृत्व गुण भरिपूर्ण छ। पाँचौं भावमा मंगल र गुरुको संयोग शिक्षा र सिर्जनामा विशेष ऊर्जा र ज्ञान ल्याउँछ। नवौं भावमा राहु हुनाले जीवनमा अनपेक्षित र अप्रचलित बाटोबाट भाग्य आउन सक्छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँ साहसी, विद्वान र परिवर्तनकारी व्यक्तित्वका धनी हुनुहुन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Bangkok Yellow Sapphire धारण गर्नु लाभदायक हुनेछ।',
    'तपाईँको वृषभ लग्नको राशिको हुनुहुन्छ। पहिलो भावमा सूर्यले तपाईँलाई स्वाभिमानी र प्रभावशाली व्यक्तित्व दिन्छ। पाँचौं भावमा मंगल र गुरुको उपस्थितिले तपाईँलाई साहसी र ज्ञानशाली बनाउँछ। नवौं भावमा राहुले अप्रत्याशित मोडबाट जीवनमा नयाँ ढोका खोल्न सक्छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन साहस र विद्याले भरिएको देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Bangkok Yellow Sapphire धारण गर्नु लाभदायक हुनेछ।',
    'पहिलो भावमा सूर्यले तपाईँमा ऊर्जा र दृढता छ तर हृदय र रक्तचापमा सचेत रहनु आवश्यक देखिन्छ। गर्मीमा थोरै बढी थकान महसुस हुन सक्छ। पानी पर्याप्त पिउनु र नियमित व्यायाम गर्नु स्वास्थ्यका लागि राम्रो हुन्छ। स्वास्थ्यलाई बलियो बनाउन Burmese Ruby धारण गर्नु उपयुक्त हुनेछ।',
    'सूर्यको प्रभावले तपाईँमा शारीरिक शक्ति र आत्मबल छ। तर कहिलेकाहीँ टाउको दुखाइ वा थकान आउन सक्छ — आराम र जलपानमा ध्यान दिनु राम्रो हुन्छ। स्वास्थ्य राम्रो राख्न Burmese Ruby धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा मंगल र गुरुको संयोगले पढाइमा जोश र गहिरो ज्ञान दुवै छ। खेलकुद, नेतृत्व वा दर्शनशास्त्रसम्बन्धी विषयमा विशेष रुचि र प्रतिभा देखिन्छ। प्रतियोगितामा जित्ने क्षमता राम्रो छ। शिक्षामा अझ उज्यालो भविष्य ल्याउन Bangkok Yellow Sapphire धारण गर्नु उत्तम हुनेछ।',
    'मंगल र गुरुको उपस्थितिले पढाइमा दृढता र विश्लेषण क्षमता उच्च छ। उच्च शिक्षा वा अनुसन्धानमा सफलता मिल्ने देखिन्छ। शिक्षामा प्रगति ल्याउन Bangkok Yellow Sapphire धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा मंगल र गुरुको संयोगले प्रेम सम्बन्धमा जोश र आदर्श दुवै छ। तपाईँ साथीसँग ईमानदार र उत्साही हुनुहुन्छ। सम्बन्धमा स्पष्टता र विश्वासले यात्रा मजबुत बनाउँछ। प्रेम सुन्दर बनाउन Red Coral धारण गर्नु लाभदायक हुनेछ।',
    'मंगल र गुरुले प्रेम सम्बन्धमा साहस र आध्यात्मिक गहिराई ल्याउँछ। साथीको सम्मान गर्नु र आफ्नो मूल्यमान्यता नछोड्नाले सम्बन्ध टिकाउ हुन्छ। प्रेमलाई मजबुत बनाउन Red Coral धारण गर्नु उपयुक्त हुनेछ।',
    'नवौं भावमा राहुले भाग्यमा अप्रत्याशित परिवर्तन र विदेश वा नयाँ ठाउँसँग सम्बन्ध देखाउँछ। जीवनमा अनौठो मोडबाट सफलता आउन सक्छ — खुला मनले अवसरहरू स्वीकार्नु राम्रो हुन्छ। भाग्य बलियो बनाउन Hessonite धारण गर्नु लाभदायक हुनेछ।',
    'राहुको प्रभावले भाग्यमा अनपेक्षित रूपमा राम्रो अवसरहरू आउन सक्छन् — तर विवेक र सतर्कतासँग कदम चाल्नु आवश्यक छ। विदेश वा प्रविधिसम्बन्धी क्षेत्रमा भाग्य उज्यालो हुन सक्छ। भाग्य सन्तुलनका लागि Hessonite धारण गर्नु उत्तम हुनेछ।',
    'Bangkok Yellow Sapphire', 'Burmese Ruby', 'Bangkok Yellow Sapphire', 'Red Coral', 'Hessonite'
);

