) VALUES (
    'मिथुन',
    'बुध',
    'शुक्र, चन्द्र',
    'सूर्य',
    'तपाईँको मिथुन लग्नको राशिको हुनुहुन्छ — चतुर, जिज्ञासु र बहुमुखी प्रतिभाका धनी। पहिलो भावमा बुधले तपाईँलाई असाधारण सञ्चारकला र तीव्र बुद्धि दिन्छ। पाँचौं भावमा शुक्र र चन्द्रको संयोग कलात्मक संवेदनशीलता र प्रेममा कोमलता ल्याउँछ। नवौं भावमा सूर्यले जीवनमा आत्मविश्वास र भाग्यको प्रकाश दिन्छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँ एक प्रतिभाशाली, प्रेमिल र आत्मनिर्भर व्यक्ति हुनुहुन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Panjshir Emerald धारण गर्नु लाभदायक हुनेछ।',
    'तपाईँको मिथुन लग्नको राशिको हुनुहुन्छ — बुद्धिमान, मिलनसार र सिर्जनशील स्वभाव। पहिलो भावमा बुधले तपाईँलाई वाकपटु र चतुर बनाउँछ। पाँचौं भावमा शुक्र र चन्द्रको उपस्थितिले कला, संगीत वा साहित्यमा विशेष प्रेम देखिन्छ। नवौं भावमा सूर्यले तपाईँलाई आफ्नो लक्ष्यप्रति दृढ र भाग्यशाली बनाउँछ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन प्रतिभा र सौभाग्यले भरिएको देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Panjshir Emerald धारण गर्नु लाभदायक हुनेछ।',
    'पहिलो भावमा बुधको उपस्थितिले तपाईँलाई मानसिक रूपमा सक्रिय राख्छ। तर अधिक सोच्ने वा तनाव लिने बानीले कहिलेकाहीँ निद्राको समस्या हुन सक्छ। मन शान्त राख्न पढाइ र प्रकृतिसँग समय बिताउनु उत्तम हुन्छ। स्वास्थ्यलाई राम्रो राख्न Panjshir Emerald धारण गर्नु लाभदायक हुनेछ।',
    'बुधको प्रभावले तपाईँको मन सधैँ व्यस्त रहन्छ — यो राम्रो कुरा हो तर मानसिक थकानबाट सचेत रहनु पनि जरुरी छ। ध्यान र लेखन जस्ता क्रियाले मन हल्का राख्न सहयोग गर्छ। स्वास्थ्य सन्तुलनका लागि Panjshir Emerald धारण गर्नु उपयुक्त हुनेछ।',
    'पाँचौं भावमा शुक्र र चन्द्रको उपस्थितिले पढाइमा भावनात्मक र सिर्जनात्मक पाटो मजबुत छ। कला, संगीत, साहित्य वा सामाजिक विज्ञानमा विशेष रुचि र प्रतिभा देखिन्छ। ध्यान केन्द्रित गर्नाले नतिजा झनै राम्रो हुन्छ। शिक्षामा उन्नति ल्याउन Pearl धारण गर्नु उत्तम हुनेछ।',
    'शुक्र र चन्द्रले पढाइमा सौन्दर्यशास्त्र र भावनात्मक बुद्धिमत्ता दिन्छ। सिर्जनात्मक क्षेत्रमा करियर बनाउन उपयुक्त देखिन्छ। शिक्षामा राम्रो प्रदर्शन ल्याउन Pearl धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा शुक्र र चन्द्रको संयोगले प्रेम सम्बन्धमा गहिरो भावना र रोमान्टिक स्वभाव देखिन्छ। तपाईँ साथीलाई ध्यान दिन र सुन्दर पल बिताउन रुचाउनुहुन्छ। सम्बन्धमा भावनात्मक सुरक्षाको आवश्यकता महसुस हुन सक्छ। प्रेम मधुर बनाउन Opal Stone धारण गर्नु लाभदायक हुनेछ।',
    'शुक्र र चन्द्रले प्रेम सम्बन्धमा असाधारण कोमलता र माया दिन्छ। तपाईँको प्रेमले साथीलाई सधैँ सुरक्षित महसुस गराउँछ। प्रेमलाई अझ सुन्दर बनाउन Opal Stone धारण गर्नु उपयुक्त हुनेछ।',
    'नवौं भावमा सूर्यको उपस्थितिले जीवनमा आत्मविश्वास र स्पष्ट दिशाबोध दिन्छ। भाग्य खुल्दा तपाईँले आफ्नो प्रतिभा र मेहनतको फल पाउन सक्नुहुन्छ। सरकारी वा नेतृत्वसम्बन्धी क्षेत्रमा अवसर आउन सक्छ। भाग्यलाई बलियो बनाउन Star Ruby धारण गर्नु लाभदायक हुनेछ।',
    'सूर्यको प्रभावले भाग्यमा आत्मविश्वास र सकारात्मक ऊर्जा छ। अनुकूल समयमा सही कदम चाल्नाले जीवनमा राम्रो परिवर्तन आउँछ। भाग्य सन्तुलनका लागि Star Ruby धारण गर्नु उत्तम हुनेछ।',
    'Panjshir Emerald', 'Panjshir Emerald', 'Pearl', 'Opal Stone', 'Star Ruby'
);

INSERT INTO gemstone_predictions (
    lagna, planets_in_1st, planets_in_5th, planets_in_9th,
    overall_prediction_male, overall_prediction_female,
    health_prediction_male, health_prediction_female,
    education_prediction_male, education_prediction_female,
    love_prediction_male, love_prediction_female,
    luck_prediction_male, luck_prediction_female,
    overall_gemstone, health_gemstone, education_gemstone, love_gemstone, luck_gemstone
) VALUES (
    'मिथुन',
    'मंगल, केतु',
    'शनि',
    'चन्द्र, गुरु',
    'तपाईँको मिथुन लग्नको राशिको हुनुहुन्छ। पहिलो भावमा मंगल र केतुको संयोग तपाईँलाई साहसी र आत्मखोजी बनाउँछ — जीवनमा गहिरो अर्थ खोज्ने स्वभाव छ। पाँचौं भावमा शनिले पढाइ र सम्बन्धमा धैर्य र अनुशासनको महत्त्व देखाउँछ। नवौं भावमा चन्द्र र गुरुको संयोग भाग्यमा भावनात्मक परिपक्वता र आध्यात्मिक विकास ल्याउँछ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन गहिरो, अर्थपूर्ण र परिवर्तनकारी छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले South Sea Pearl धारण गर्नु लाभदायक हुनेछ।',
    'तपाईँको मिथुन लग्नको राशिको हुनुहुन्छ। पहिलो भावमा मंगल र केतुले तपाईँलाई जिज्ञासु र स्वतन्त्र स्वभावकी बनाउँछ। पाँचौं भावमा शनिको उपस्थितिले जीवनका महत्त्वपूर्ण कुरामा गम्भीरता ल्याउँछ। नवौं भावमा चन्द्र र गुरुको संयोगले भाग्य र आध्यात्मिक यात्रा दुवैलाई अर्थपूर्ण बनाउँछ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन गहिरो आत्मसाक्षात्कारतर्फ अग्रसर देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले South Sea Pearl धारण गर्नु लाभदायक हुनेछ।',
    'पहिलो भावमा मंगल र केतुको उपस्थितिले शारीरिक ऊर्जा उच्च छ तर कहिलेकाहीँ चोटपटक वा दुर्घटनाबाट सचेत रहनु आवश्यक छ। आत्मिक शान्तिका लागि ध्यान वा प्रकृतिमा समय बिताउनु राम्रो हुन्छ। स्वास्थ्यलाई सन्तुलित राख्न Cats Eye धारण गर्नु लाभदायक हुनेछ।',
    'मंगल र केतुको संयोगले शरीरमा ऊर्जा त छ तर मानसिक शान्तिका लागि विशेष ध्यान दिनु आवश्यक छ। योग र ध्यानले उत्तम सहयोग पुर्‍याउँछ। स्वास्थ्य राम्रो राख्न Cats Eye धारण गर्नु उपयुक्त हुनेछ।',
    'पाँचौं भावमा शनिले पढाइमा मेहनत र अनुशासनको महत्त्व देखाउँछ। छिटो परिणाम नआए पनि निरन्तर प्रयासले अन्ततः सफलता मिल्छ। गहिरो र व्यावहारिक विषयमा तपाईँको रुचि र क्षमता उत्कृष्ट छ। शिक्षामा सफलता ल्याउन Iolite धारण गर्नु उत्तम हुनेछ।',
    'शनिको प्रभावले पढाइमा गम्भीरता र दृढता छ। परिणाम ढिलो आए पनि तपाईँले अन्ततः आफ्नो लक्ष्य पाउनुहुन्छ। शिक्षामा प्रगति ल्याउन Iolite धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा शनिले प्रेम सम्बन्धमा जिम्मेवारी र परिपक्वताको आवश्यकता देखाउँछ। सम्बन्ध सुरु गर्न थोडा ढिलाइ हुन सक्छ तर एकपटक बनेको सम्बन्ध टिकाउ हुन्छ। विश्वास र धैर्यले सम्बन्धलाई मजबुत बनाउँछ। प्रेमलाई सुरक्षित बनाउन Iolite धारण गर्नु लाभदायक हुनेछ।',
    'शनिले प्रेम सम्बन्धमा गम्भीरता र प्रतिबद्धतालाई महत्त्व दिन्छ। तपाईँ दीर्घकालीन सम्बन्धमा विश्वास गर्नुहुन्छ। सम्बन्धलाई टिकाउ बनाउन Iolite धारण गर्नु उपयुक्त हुनेछ।',
    'नवौं भावमा चन्द्र र गुरुको संयोगले भाग्यमा भावनात्मक समृद्धि र ज्ञानको प्रकाश दिन्छ। आध्यात्मिक यात्रा वा गुरुजनको मार्गदर्शनले जीवनलाई सही दिशामा लैजान्छ। भाग्यलाई बलियो बनाउन South Sea Pearl धारण गर्नु लाभदायक हुनेछ।',
    'चन्द्र र गुरुको संयोगले भाग्यमा माया, करुणा र ज्ञान सबै एकसाथ आउँछ। जीवनमा अनुकूल अवसरहरू स्वाभाविक रूपमा आउन सक्छन्। भाग्य सन्तुलनका लागि South Sea Pearl धारण गर्नु उत्तम हुनेछ।',
    'South Sea Pearl', 'Cats Eye', 'Iolite', 'Iolite', 'South Sea Pearl'
);

