    love_prediction_male, love_prediction_female,
    luck_prediction_male, luck_prediction_female,
    overall_gemstone, health_gemstone, education_gemstone, love_gemstone, luck_gemstone
) VALUES (
    'सिंह',
    'सूर्य',
    'मंगल, बुध',
    'गुरु, चन्द्र',
    'तपाईँको सिंह लग्नको राशिको हुनुहुन्छ — तेजस्वी, नेतृत्वकारी र स्वाभिमानी व्यक्तित्व। पहिलो भावमा सूर्यले तपाईँलाई असाधारण आत्मविश्वास र प्रभाव दिन्छ — तपाईँ जुन कोठामा पस्नुहुन्छ, त्यहाँ तपाईँको उपस्थिति महसुस हुन्छ। पाँचौं भावमा मंगल र बुधको संयोग तपाईँलाई साहसी बौद्धिक र कुशल वक्ता बनाउँछ। नवौं भावमा गुरु र चन्द्रको संयोगले भाग्यमा ज्ञान, करुणा र आनन्द ल्याउँछ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन उज्यालो, सफल र प्रेरणादायी देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Burmese Ruby धारण गर्नु लाभदायक हुनेछ।',
    'तपाईँको सिंह लग्नको राशिको हुनुहुन्छ — आत्मविश्वासी, तेजस्वी र नेतृत्व गर्न सक्षम। पहिलो भावमा सूर्यले तपाईँमा राजसी व्यक्तित्व र स्वाभिमान दिन्छ। पाँचौं भावमा मंगल र बुधको संयोगले तपाईँलाई बौद्धिक रूपमा तीक्ष्ण र साहसी बनाउँछ। नवौं भावमा गुरु र चन्द्रको उपस्थितिले भाग्यमा माया र ज्ञान दुवै दिन्छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन प्रभावशाली, मिलनसार र सफल देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Burmese Ruby धारण गर्नु लाभदायक हुनेछ।',
    'पहिलो भावमा सूर्यले तपाईँमा जीवनशक्ति र ऊर्जा भरपूर छ। हृदय र रक्तचापमा सचेत रहनु राम्रो हुन्छ। नियमित व्यायाम र स्वस्थ जीवनशैलीले दीर्घायु सुनिश्चित गर्छ। स्वास्थ्यलाई बलियो राख्न African Ruby धारण गर्नु उत्तम हुनेछ।',
    'सूर्यको प्रभावले तपाईँमा शारीरिक शक्ति र आत्मिक बल उत्कृष्ट छ। गर्मीमा थोडा बढी ख्याल राख्नु आवश्यक हुन सक्छ। स्वास्थ्य राम्रो राख्न African Ruby धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा मंगल र बुधको संयोगले पढाइमा तीव्र सोचशक्ति र उत्साह छ। बहस, तर्क वा नेतृत्वसम्बन्धी गतिविधिमा अग्रस्थानमा रहन्छन्। प्रतियोगितात्मक परीक्षामा सफलता मिल्ने सम्भावना राम्रो छ। शिक्षामा अझ सफलता ल्याउन Carnelian धारण गर्नु उत्तम हुनेछ।',
    'मंगल र बुधको संयोगले पढाइमा चपलता र उत्साह दिन्छ। नेतृत्व वा व्यावसायिक शिक्षामा विशेष रुचि र सफलता देखिन्छ। शिक्षामा प्रगति ल्याउन Carnelian धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा मंगल र बुधले प्रेम सम्बन्धमा उत्साह र बौद्धिक आकर्षण दिन्छ। तपाईँ साथीसँग खुलेर भावना अभिव्यक्त गर्न सक्नुहुन्छ। सम्बन्धमा जोश र पारदर्शिता राखिनु राम्रो हुन्छ। प्रेमलाई सुन्दर बनाउन Ruby Stone धारण गर्नु लाभदायक हुनेछ।',
    'मंगल र बुधले प्रेम सम्बन्धमा जोश र संवाद दुवैको महत्त्व बताउँछ। आफ्नो भावना स्पष्ट रूपमा भन्नाले सम्बन्ध राम्रो हुन्छ। प्रेमलाई मजबुत बनाउन Ruby Stone धारण गर्नु उपयुक्त हुनेछ।',
    'नवौं भावमा गुरु र चन्द्रको संयोगले भाग्यमा गहिरो ज्ञान र भावनात्मक परिपक्वता ल्याउँछ। धर्म, अध्यात्म वा उच्च शिक्षामा अवसर आउन सक्छ। भाग्यलाई बलियो बनाउन Yellow Sapphire धारण गर्नु लाभदायक हुनेछ।',
    'गुरु र चन्द्रको संयोगले भाग्यमा माया, ज्ञान र आनन्द तिनै एकसाथ आउँछ। अनुकूल समयमा राम्रा अवसरहरू स्वाभाविक रूपमा आउन सक्छन्। भाग्य सन्तुलनका लागि Yellow Sapphire धारण गर्नु उत्तम हुनेछ।',
    'Burmese Ruby', 'African Ruby', 'Carnelian', 'Ruby Stone', 'Yellow Sapphire'
);

