    overall_gemstone, health_gemstone, education_gemstone, love_gemstone, luck_gemstone
) VALUES (
    'कन्या',
    'बुध, शुक्र',
    'शनि',
    'गुरु',
    'तपाईँको कन्या लग्नको राशिको हुनुहुन्छ — विश्लेषणात्मक, परिश्रमी र व्यवस्थाप्रिय स्वभाव। पहिलो भावमा बुध र शुक्रको संयोग तपाईँलाई बुद्धिमान र सौन्दर्यप्रिय दुवै बनाउँछ। पाँचौं भावमा शनिले पढाइ र सम्बन्धमा जिम्मेवारी र धैर्यको पाठ दिन्छ। नवौं भावमा गुरुले जीवनमा ज्ञान र भाग्यको प्रकाश ल्याउँछ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन मेहनत र ज्ञानको बाटोमा हिँडेको एक सफल यात्री जस्तो देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Citrine धारण गर्नु लाभदायक हुनेछ।',
    'तपाईँको कन्या लग्नको राशिको हुनुहुन्छ — व्यवस्थित, मेहनती र सेवाभावी स्वभाव। पहिलो भावमा बुध र शुक्रले तपाईँलाई चतुर, सुकोमल र आकर्षक बनाउँछ। पाँचौं भावमा शनिको उपस्थितिले पढाइ र जीवनमा गम्भीरता र अनुशासन ल्याउँछ। नवौं भावमा गुरुले भाग्यमा ज्ञान र अध्यात्मको रंग थप्छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन अनुशासन, बुद्धि र करुणाले भरिएको सुन्दर यात्रा देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Citrine धारण गर्नु लाभदायक हुनेछ।',
    'बुध र शुक्रको संयोगले तपाईँलाई शारीरिक रूपमा कोमल र मानसिक रूपमा सक्रिय बनाउँछ। पाचनतन्त्र र त्वचामा थोडा ध्यान दिनु आवश्यक हुन सक्छ। ताजा खाना र जलपानले स्वास्थ्य राम्रो राख्न सकिन्छ। स्वास्थ्यलाई सन्तुलित राख्न Russian Emerald धारण गर्नु लाभदायक हुनेछ।',
    'बुध र शुक्रको प्रभावले तपाईँमा शारीरिक सुन्दरता र मानसिक संवेदनशीलता दुवै छ। तनाव र थकानलाई बेलैमा सम्बोधन गर्नु जरुरी छ। स्वास्थ्य राम्रो राख्न Russian Emerald धारण गर्नु उपयुक्त हुनेछ।',
    'पाँचौं भावमा शनिले पढाइमा मेहनत र व्यवस्थाको आवश्यकता देखाउँछ। लामो समयको अध्ययनले सफलता मिल्छ — छिटो परिणाम खोज्नु हुँदैन। विज्ञान, इञ्जिनियरिङ वा प्रशासनिक विषयमा सफलता मिल्ने देखिन्छ। शिक्षामा उन्नति ल्याउन Pitambari Neelam धारण गर्नु उत्तम हुनेछ।',
    'शनिको प्रभावले पढाइमा व्यवस्था र अनुशासनले उत्कृष्ट परिणाम आउँछ। नियमित अभ्यासले जटिल विषय पनि सहज हुन्छ। शिक्षामा प्रगति ल्याउन Pitambari Neelam धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा शनिले प्रेम सम्बन्धमा जिम्मेवारी र परिपक्वतालाई महत्त्व दिन्छ। तपाईँ गम्भीर र दीर्घकालीन सम्बन्धमा विश्वास गर्नुहुन्छ। समयसँगै सम्बन्ध गहिरो र बलियो हुन्छ। प्रेम सम्बन्ध मजबुत बनाउन Blue Sapphire धारण गर्नु लाभदायक हुनेछ।',
    'शनिले प्रेम सम्बन्धमा विश्वास र जिम्मेवारीलाई केन्द्रमा राख्छ। सही साथीसँग बनेको सम्बन्ध जीवनभर टिकाउ हुन्छ। प्रेमलाई गहिरो बनाउन Blue Sapphire धारण गर्नु उपयुक्त हुनेछ।',
    'नवौं भावमा गुरुले जीवनमा ज्ञान, आध्यात्मिक विकास र भाग्य सबै एकसाथ ल्याउँछ। शिक्षा, धर्म वा यात्राको माध्यमबाट जीवनमा राम्रा अवसरहरू आउन सक्छन्। भाग्यलाई बलियो बनाउन Citrine धारण गर्नु लाभदायक हुनेछ।',
    'गुरुको प्रभावले भाग्यमा ज्ञान र आध्यात्मिकताले अवसर ल्याउँछ। जीवनमा राम्रा मान्छेहरूको संगत भाग्यलाई उज्यालो बनाउँछ। भाग्य ल्याउन Citrine धारण गर्नु उत्तम हुनेछ।',
    'Citrine', 'Russian Emerald', 'Pitambari Neelam', 'Blue Sapphire', 'Citrine'
);

