    love_prediction_male, love_prediction_female,
    luck_prediction_male, luck_prediction_female,
    overall_gemstone, health_gemstone, education_gemstone, love_gemstone, luck_gemstone
) VALUES (
    'मकर',
    'राहु, मंगल',
    'चन्द्र, बुध',
    'केतु, शनि',
    'तपाईँको मकर लग्नको राशिको हुनुहुन्छ। पहिलो भावमा राहु र मंगलको संयोगले तपाईँलाई साहसी, परिवर्तनकारी र जोखिम लिन सक्ने व्यक्तित्व दिन्छ। पाँचौं भावमा चन्द्र र बुधको संयोग पढाइ र सिर्जनामा भावनात्मक बुद्धिमत्ता र तीक्ष्णता ल्याउँछ। नवौं भावमा केतु र शनिको संयोगले भाग्यमा आध्यात्मिक गहिराई र कर्मको महत्त्व देखाउँछ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन एक असाधारण र गहिरो यात्रा हो। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Howlite धारण गर्नु लाभदायक हुनेछ।',
    'तपाईँको मकर लग्नको राशिको हुनुहुन्छ। पहिलो भावमा राहु र मंगलले तपाईँलाई साहसी र निर्भीक बनाउँछ। पाँचौं भावमा चन्द्र र बुधको संयोगले तपाईँलाई भावनात्मक रूपमा बुद्धिमान बनाउँछ। नवौं भावमा केतु र शनिले भाग्यमा आत्मिक विकास र कर्मको पाठ सिकाउँछ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन गहिरो आत्मज्ञानतर्फको यात्रा हो। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Howlite धारण गर्नु लाभदायक हुनेछ।',
    'राहु र मंगलको संयोगले शरीरमा उच्च ऊर्जा छ तर अनावश्यक जोखिम र चोटपटकबाट सचेत रहनु आवश्यक छ। मन शान्त राख्न ध्यान र नियमित आराम आवश्यक छ। स्वास्थ्यलाई सन्तुलित राख्न Bloodstone धारण गर्नु लाभदायक हुनेछ।',
    'राहु र मंगलको प्रभावले शरीरमा ऊर्जा र मनमा तीव्रता छ। मानसिक र शारीरिक सन्तुलनका लागि नियमित ध्यान र व्यायाम राम्रो हुन्छ। स्वास्थ्य राम्रो राख्न Bloodstone धारण गर्नु उपयुक्त हुनेछ।',
    'पाँचौं भावमा चन्द्र र बुधको संयोगले पढाइमा स्मरण शक्ति, भावनात्मक बुद्धिमत्ता र तर्कशक्ति उत्कृष्ट छ। मनोविज्ञान, साहित्य वा संवादसम्बन्धी विषयमा विशेष रुचि छ। शिक्षामा अझ सफलता ल्याउन Moonstone धारण गर्नु उत्तम हुनेछ।',
    'चन्द्र र बुधको संयोगले पढाइमा भावनात्मक बुझाइ र विश्लेषण क्षमता दुवै छ। सिर्जनात्मक र सञ्चारसम्बन्धी क्षेत्रमा सफलता मिल्ने देखिन्छ। शिक्षामा प्रगति ल्याउन Moonstone धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा चन्द्र र बुधले प्रेम सम्बन्धमा कोमलता, बुद्धि र संवादको महत्त्व देखाउँछ। तपाईँ साथीको मन राम्ररी बुझ्न सक्नुहुन्छ। भावना र तर्क दुवैको मिश्रणले सम्बन्ध सुन्दर हुन्छ। प्रेम सम्बन्ध गहिरो बनाउन Keshi Pearl धारण गर्नु लाभदायक हुनेछ।',
    'चन्द्र र बुधले प्रेम सम्बन्धमा संवेदनशीलता र संवादकला दिन्छ। साथीसँग खुलेर कुरा गर्नाले सम्बन्ध मजबुत हुन्छ। प्रेमलाई सुन्दर बनाउन Keshi Pearl धारण गर्नु उपयुक्त हुनेछ।',
    'नवौं भावमा केतु र शनिको संयोगले भाग्यमा आध्यात्मिक पथ र कर्मको महत्त्व बताउँछ। वैरागी वा अनुसन्धानी मनले जीवनमा अनौठो सत्य भेट्न सकिन्छ। भाग्यलाई बलियो बनाउन Howlite धारण गर्नु लाभदायक हुनेछ।',
    'केतु र शनिले भाग्यमा आत्मिक विकास र कर्मको पाठ दिन्छ। आफ्नो आन्तरिक यात्रामा ध्यान दिनाले जीवनमा गहिरो सन्तुष्टि आउँछ। भाग्य ल्याउन Howlite धारण गर्नु उत्तम हुनेछ।',
    'Howlite', 'Bloodstone', 'Moonstone', 'Keshi Pearl', 'Howlite'
);

