) VALUES (
    'मीन',
    'गुरु, शुक्र',
    'चन्द्र, बुध',
    'सूर्य',
    'तपाईँको मीन लग्नको राशिको हुनुहुन्छ — सहानुभूतिशील, सिर्जनशील र आध्यात्मिक स्वभाव। पहिलो भावमा गुरु र शुक्रको संयोग तपाईँलाई ज्ञानी, सौन्दर्यप्रिय र दयालु बनाउँछ। पाँचौं भावमा चन्द्र र बुधको संयोगले भावनात्मक बुद्धिमत्ता र तीक्ष्ण सञ्चारकला ल्याउँछ। नवौं भावमा सूर्यले जीवनमा आत्मविश्वास, स्पष्ट उद्देश्य र भाग्यको प्रकाश दिन्छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन असाधारण रूपमा समृद्ध, अर्थपूर्ण र आत्मिक रूपमा परिपूर्ण देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Rubellite धारण गर्नु लाभदायक हुनेछ।',
    'तपाईँको मीन लग्नको राशिको हुनुहुन्छ — करुणामयी, कल्पनाशीला र गहिरो भावनाका धनी। पहिलो भावमा गुरु र शुक्रले तपाईँलाई सुन्दर, ज्ञानी र सहानुभूतिशील बनाउँछ। पाँचौं भावमा चन्द्र र बुधको संयोगले पढाइ र प्रेममा भावना र बुद्धिको सन्तुलन छ। नवौं भावमा सूर्यले भाग्यमा आत्मविश्वास र स्पष्टता ल्याउँछ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन करुणा, बुद्धि र उज्यालोले भरिएको देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Rubellite धारण गर्नु लाभदायक हुनेछ।',
    'गुरु र शुक्रको संयोगले तपाईँलाई शारीरिक सौन्दर्य र मानसिक प्रसन्नता दिन्छ। कहिलेकाहीँ थकान वा अधिक भावुकताले स्वास्थ्यमा असर पर्न सक्छ — आफ्नो लागि समय निकाल्नु जरुरी छ। स्वास्थ्यलाई सन्तुलित राख्न Opal Stone धारण गर्नु लाभदायक हुनेछ।',
    'गुरु र शुक्रले तपाईँलाई स्वास्थ्यमा सुन्दरता र प्रसन्नता दिन्छ। भावनात्मक स्वास्थ्यमा विशेष ध्यान दिनु आवश्यक छ — आफूलाई माया गर्नु सिक्नु राम्रो हुन्छ। स्वास्थ्य राम्रो राख्न Opal Stone धारण गर्नु उपयुक्त हुनेछ।',
    'पाँचौं भावमा चन्द्र र बुधको संयोगले पढाइमा भावनात्मक बुद्धिमत्ता र तीव्र सञ्चारकला छ। साहित्य, भाषाशास्त्र वा मनोविज्ञानमा विशेष प्रतिभा र रुचि देखिन्छ। शिक्षामा अझ उन्नति ल्याउन Zambian Emerald धारण गर्नु उत्तम हुनेछ।',
    'चन्द्र र बुधले पढाइमा संवेदनशीलता र बौद्धिक तीक्ष्णता दुवै दिन्छ। लेखन, शिक्षण वा परामर्शसम्बन्धी क्षेत्रमा सफलता देखिन्छ। शिक्षामा प्रगति ल्याउन Zambian Emerald धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा चन्द्र र बुधले प्रेम सम्बन्धमा गहिरो भावना र बौद्धिक आकर्षण ल्याउँछ। तपाईँ साथीसँग मन र बुद्धि दुवैले जोडिनु चाहनुहुन्छ। संवाद र कोमलताले सम्बन्धलाई अझ गहिरो बनाउँछ। प्रेम सम्बन्ध मधुर बनाउन Rubellite धारण गर्नु लाभदायक हुनेछ।',
    'चन्द्र र बुधले प्रेम सम्बन्धमा भावनात्मक बुझाइ र बौद्धिक सम्बन्ध दिन्छ। साथीसँग गहिरो र अर्थपूर्ण वार्तालापले सम्बन्ध मजबुत हुन्छ। प्रेमलाई सुन्दर बनाउन Rubellite धारण गर्नु उपयुक्त हुनेछ।',
    'नवौं भावमा सूर्यले भाग्यमा आत्मविश्वास र उद्देश्यको स्पष्टता ल्याउँछ। नेतृत्व, शिक्षा वा सार्वजनिक सेवामा भाग्य उज्यालो हुन सक्छ। भाग्यलाई बलियो बनाउन Ruby Stone धारण गर्नु लाभदायक हुनेछ।',
    'सूर्यको प्रभावले भाग्यमा आत्मिक प्रकाश र स्पष्ट दिशा ल्याउँछ। आफ्नो उद्देश्यप्रति दृढ रहनाले जीवनमा राम्रो परिवर्तन आउँछ। भाग्य ल्याउन Ruby Stone धारण गर्नु उत्तम हुनेछ।',
    'Rubellite', 'Opal Stone', 'Zambian Emerald', 'Rubellite', 'Ruby Stone'
);

INSERT INTO gemstone_predictions (
    lagna, planets_in_1st, planets_in_5th, planets_in_9th,
    overall_prediction_male, overall_prediction_female,
    health_prediction_male, health_prediction_female,
    education_prediction_male, education_prediction_female,
    love_prediction_male, love_prediction_female,
    luck_prediction_male, luck_prediction_female,
    overall_gemstone, health_gemstone, education_gemstone, love_gemstone, luck_gemstone
) VALUES (
    'मीन',
    'केतु, शनि',
    'राहु, सूर्य',
    'मंगल, शुक्र',
    'तपाईँको मीन लग्नको राशिको हुनुहुन्छ। पहिलो भावमा केतु र शनिको संयोगले तपाईँलाई वैरागी, गहिरो विचारक र आत्मखोजी बनाउँछ। पाँचौं भावमा राहु र सूर्यको संयोगले पढाइ र सिर्जनामा अप्रत्याशित ऊर्जा र नेतृत्व क्षमता ल्याउँछ। नवौं भावमा मंगल र शुक्रको संयोगले भाग्यमा साहस र सौन्दर्यको रोचक मेल छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन रहस्यमय, शक्तिशाली र अनौठो सुन्दरताले भरिएको देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Bi-Color Tourmaline धारण गर्नु लाभदायक हुनेछ।',
    'तपाईँको मीन लग्नको राशिको हुनुहुन्छ। पहिलो भावमा केतु र शनिले तपाईँलाई रहस्यमय, गहिरो र अनुशासित बनाउँछ। पाँचौं भावमा राहु र सूर्यको उपस्थितिले पढाइ र सिर्जनामा अनौठो ऊर्जा र तेज देखिन्छ। नवौं भावमा मंगल र शुक्रको संयोगले भाग्यमा साहस र कलाको सुन्दर संगम छ। यी तीनै भावको संयुक्त प्रभाव हेर्दा तपाईँको जीवन गहिरो, शक्तिशाली र अर्थपूर्ण देखिन्छ। तपाईँको जीवनमा सन्तुलन ल्याउन तपाईँले Bi-Color Tourmaline धारण गर्नु लाभदायक हुनेछ।',
    'केतु र शनिको संयोगले तपाईँमा मानसिक गहिराई छ — तर एकाकीपन वा अवसादको भावना कहिलेकाहीँ आउन सक्छ। सकारात्मक संगत र आत्मिक अभ्यासले मन उज्यालो रहन्छ। स्वास्थ्यलाई राम्रो राख्न Cats Eye धारण गर्नु लाभदायक हुनेछ।',
    'केतु र शनिले तपाईँलाई गहिरो विचारक बनाउँछ — तर मानसिक शान्तिका लागि विशेष ध्यान दिनु आवश्यक छ। ध्यान, सङ्गीत वा प्रकृतिसँगको सम्बन्धले स्वास्थ्य राम्रो राख्छ। स्वास्थ्य सन्तुलनका लागि Cats Eye धारण गर्नु उपयुक्त हुनेछ।',
    'पाँचौं भावमा राहु र सूर्यको संयोगले पढाइमा अप्रत्याशित प्रतिभा र नेतृत्व देखिन्छ। आधुनिक प्रविधि, नेतृत्व वा कलासम्बन्धी क्षेत्रमा विशेष सफलता मिल्ने देखिन्छ। शिक्षामा अझ उन्नति ल्याउन Zircon - Jarkan धारण गर्नु उत्तम हुनेछ।',
    'राहु र सूर्यको संयोगले पढाइमा अनौठो तेज र नवीनता देखिन्छ। अपरम्परागत क्षेत्रमा उत्कृष्ट सफलता मिल्ने सम्भावना छ। शिक्षामा प्रगति ल्याउन Zircon - Jarkan धारण गर्नु लाभदायक हुनेछ।',
    'पाँचौं भावमा राहु र सूर्यले प्रेम सम्बन्धमा अनपेक्षित र तीव्र आकर्षण देखाउँछ। सम्बन्धमा स्पष्टता र विवेक राख्नु आवश्यक छ। सही साथीसँग सम्बन्ध भयो भने जीवन बद्लिन सक्छ। प्रेम सम्बन्ध सन्तुलित बनाउन Hessonite धारण गर्नु लाभदायक हुनेछ।',
    'राहु र सूर्यले प्रेम सम्बन्धमा रोमाञ्चकारी आकर्षण ल्याउँछ तर विवेकसाथ अगाडि बढ्नु राम्रो हुन्छ। सही समयमा सही निर्णय लिनाले सम्बन्ध टिकाउ हुन्छ। प्रेमलाई सुरक्षित बनाउन Hessonite धारण गर्नु उपयुक्त हुनेछ।',
    'नवौं भावमा मंगल र शुक्रको संयोगले भाग्यमा साहस र सौन्दर्यको अनौठो मेल छ। कला, खेलकुद वा उद्यमशीलतामा भाग्य उज्यालो हुन सक्छ। जीवनमा हिम्मत र सुरुचिले अवसर खोल्न सकिन्छ। भाग्यलाई बलियो बनाउन Bi-Color Tourmaline धारण गर्नु लाभदायक हुनेछ।',
    'मंगल र शुक्रले भाग्यमा उत्साह र सौन्दर्यको रोचक मेल ल्याउँछ। साहस र कलात्मकताले जीवनमा नयाँ ढोकाहरू खोल्छन्। भाग्य ल्याउन Bi-Color Tourmaline धारण गर्नु उत्तम हुनेछ।',
    'Bi-Color Tourmaline', 'Cats Eye', 'Zircon - Jarkan', 'Hessonite', 'Bi-Color Tourmaline'
);

